import React, { useState } from 'react';
import SEOHead from '../components/SEOHead';

export default function OhmsLaw() {
  const [v, setV] = useState('');
  const [i, setI] = useState('');
  const [r, setR] = useState('');
  const [p, setP] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  const calculate = () => {
    setError('');
    const V = parseFloat(v);
    const I = parseFloat(i);
    const R = parseFloat(r);
    const P = parseFloat(p);

    let count = [v, i, r, p].filter(x => x !== '').length;
    if (count < 2) {
      setError('Please enter at least two values.');
      return;
    }

    let resV = V, resI = I, resR = R, resP = P;

    // V and I
    if (v !== '' && i !== '') {
      resR = V / I;
      resP = V * I;
    }
    // V and R
    else if (v !== '' && r !== '') {
      resI = V / R;
      resP = (V * V) / R;
    }
    // V and P
    else if (v !== '' && p !== '') {
      resI = P / V;
      resR = (V * V) / P;
    }
    // I and R
    else if (i !== '' && r !== '') {
      resV = I * R;
      resP = I * I * R;
    }
    // I and P
    else if (i !== '' && p !== '') {
      resV = P / I;
      resR = P / (I * I);
    }
    // R and P
    else if (r !== '' && p !== '') {
      resV = Math.sqrt(P * R);
      resI = Math.sqrt(P / r);
    }

    setResult({ v: resV, i: resI, r: resR, p: resP });
  };

  const clear = () => {
    setV(''); setI(''); setR(''); setP(''); setResult(null); setError('');
  };

  return (
    <>
      <SEOHead
        title="Ohm's Law Calculator – V I R P | PoolCalculator"
        description="Solve for Voltage, Current, Resistance, or Power using Ohm's law. Simple online calculator for electronics enthusiasts."
        keywords="ohms law calculator, voltage calculator, current calculator, power calculator, electronics tools"
        canonical="/ohms-law"
      />
      <div className="page-wrapper">
        <div className="container">
          <div className="ad-slot ad-slot-banner">Top Banner Advertisement</div>
          <div className="page-header">
            <h1>Ohm's Law Calculator</h1>
            <p>Calculate Voltage (V), Current (I), Resistance (R), and Power (P) by entering any two values.</p>
          </div>

          <div className="calc-layout">
            <div className="card">
              <div className="section-title">Enter any two values</div>
              <div className="input-group">
                <label>Voltage (V) - Volts</label>
                <input type="number" value={v} onChange={e => setV(e.target.value)} placeholder="e.g. 12" />
              </div>
              <div className="input-group">
                <label>Current (I) - Amperes</label>
                <input type="number" value={i} onChange={e => setI(e.target.value)} placeholder="e.g. 0.5" />
              </div>
              <div className="input-group">
                <label>Resistance (R) - Ohms</label>
                <input type="number" value={r} onChange={e => setR(e.target.value)} placeholder="e.g. 24" />
              </div>
              <div className="input-group">
                <label>Power (P) - Watts</label>
                <input type="number" value={p} onChange={e => setP(e.target.value)} placeholder="e.g. 6" />
              </div>
              {error && <p style={{color:'var(--error)',fontSize:'13px',marginBottom:'12px'}}>{error}</p>}
              <div style={{display:'flex',gap:'10px'}}>
                <button className="btn-primary" onClick={calculate}>Calculate</button>
                <button className="btn-secondary" onClick={clear}>Clear All</button>
              </div>
            </div>

            <div className="hero-image-container">
              <img src="/images/calculator_resistor.png" alt="Ohm's Law Diagram" className="hero-img" />
            </div>
          </div>

          {result && (
            <div className="result-section">
              <div className="card">
                <div className="section-title">Calculated Values</div>
                <div className="result-box">
                  <div className="result-item highlight">
                    <span className="result-label">Voltage (V)</span>
                    <span className="result-value">{result.v.toFixed(3)} V</span>
                  </div>
                  <div className="result-item highlight">
                    <span className="result-label">Current (I)</span>
                    <span className="result-value">{result.i.toFixed(3)} A</span>
                  </div>
                  <div className="result-item">
                    <span className="result-label">Resistance (R)</span>
                    <span className="result-value">{result.r.toFixed(3)} Ω</span>
                  </div>
                  <div className="result-item">
                    <span className="result-label">Power (P)</span>
                    <span className="result-value">{result.p.toFixed(3)} W</span>
                  </div>
                </div>
              </div>
              <div className="ad-slot ad-slot-banner">Below Result Advertisement</div>
            </div>
          )}

          <div className="description-section card">
            <div className="description-layout">
              <div className="description-image">
                <img src="/images/calculator_descrip_resistor.png" alt="Ohm's Law Triangle" />
              </div>
              <div className="description-text">
                <div className="section-title">Understanding Ohm's Law</div>
                <p>
                  Ohm's Law is the most fundamental rule in electronics. it describes the relationship between voltage, current, and resistance in an electrical circuit.
                </p>
                <div className="formula-box">
                  <h3>Primary Formulas</h3>
                  <code>V = I × R</code>
                  <code>I = V / R</code>
                  <code>R = V / I</code>
                </div>
                <div className="formula-box">
                  <h3>Power Formulas</h3>
                  <code>P = V × I</code>
                  <code>P = I² × R</code>
                  <code>P = V² / R</code>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
